fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    let mut popcount_depths = vec![0; n];

    // Precompute popcount-depth for each number in nums
    for i in 0..n {
        let mut current = nums[i];
        let mut d = 0;
        while current > 0 {
            current = current.count_ones() as i64;
            d += 1;
        }
        popcount_depths[i] = d;
    }

    let mut answer = Vec::new();

    // Process each query
    for q in queries {
        if q[0] == 1 {
            let l = q[1] as usize;
            let r = q[2] as usize;
            let k = q[3] as usize;
            let mut count = 0;
            for i in l..=r {
                if popcount_depths[i] == k {
                    count += 1;
                }
            }
            answer.push(count as i64);
        } else {
            let idx = q[1] as usize;
            let val = q[2];
            nums[idx] = val;
            let mut current = val;
            let mut d = 0;
            while current > 0 {
                current = current.count_ones() as i64;
                d += 1;
            }
            popcount_depths[idx] = d;
        }
    }

    answer
}
